SELECT EXISTS(
    SELECT 1
      FROM com.tn_vrfcn_assgn
     WHERE vrfcn_inst_id = #{vrfcnInstId}
       AND oprtr_id      = #{oprtrId}
       AND rprt_yr       = #{rprtYr}
       AND NOW() BETWEEN use_bgng_dt AND use_end_dt
)

SELECT oprtr_id
  FROM com.tn_vrfcn_assgn
 WHERE vrfcn_inst_id = #{vrfcnInstId}
   AND rprt_yr       = #{rprtYr}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
 ORDER BY oprtr_id

mapper.update:
UPDATE com.tn_vrfcn_assgn
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE vrfcn_inst_id = #{vrfcnInstId}
   AND oprtr_id      = #{oprtrId}
   AND rprt_yr       = #{rprtYr}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
